import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

interface Props {
  currentTemp: number;
  condition: 'sunny' | 'cloudy' | 'rainy';
  humidity: number;
  windSpeed: number;
  forecast: { day: string; icon: string; high: number; low: number }[];
}

function useComponent(props: Props) {
  const getConditionIcon = useCallback((condition: string) => {
    switch (condition) {
      case 'sunny': return '☀️';
      case 'cloudy': return '☁️';
      case 'rainy': return '🌧️';
      default: return '❓';
    }
  }, []);

  return { ...props, getConditionIcon };
}

export default function Component(props: Props) {
  const { currentTemp, condition, humidity, windSpeed, forecast, getConditionIcon } = useComponent(props);

  return (
    <Card padding={24} shadow="md" radius="lg">
      <Stack gap={16}>
        <Row justify="between" align="center">
          <Heading level={2}>Current Weather</Heading>
          <Text variant="bodyLarge">{getConditionIcon(condition)} {condition.toUpperCase()}</Text>
        </Row>
        <Text size="4xl" weight="bold">{currentTemp}°C</Text>
        <Row gap={24}>
          <Text variant="bodySmall">Humidity: {humidity}%</Text>
          <Text variant="bodySmall">Wind: {windSpeed} km/h</Text>
        </Row>
        <Divider margin={8} />
        <Stack direction="horizontal" gap={16} justify="between">
          {forecast.map((f, i) => (
            <Stack key={i} align="center" gap={4}>
              <Text variant="caption">{f.day}</Text>
              <Text>{f.icon}</Text>
              <Text variant="bodySmall" weight="semibold">{f.high}°</Text>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{f.low}°</Text>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Box, Text, Heading, Divider, Input } from '@ggui-ai/design/primitives';

interface Props {
  elements: {
    atomicNumber: number;
    symbol: string;
    name: string;
    atomicWeight: number;
    category: string;
    row: number;
    column: number;
  }[];
}

function useComponent(props: Props) {
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<Props['elements'][0] | null>(null);

  const filtered = useMemo(() => {
    const s = search.toLowerCase();
    return props.elements.filter(e => 
      e.name.toLowerCase().includes(s) || e.symbol.toLowerCase().includes(s)
    );
  }, [props.elements, search]);

  const categories = useMemo(() => Array.from(new Set(props.elements.map(e => e.category))), [props.elements]);

  const getCategoryColor = (category: string) => {
    const map: Record<string, string> = {
      'noble gas': 'var(--ggui-color-info-500, #06b6d4)',
      'alkali metal': 'var(--ggui-color-error-500, #ef4444)',
      'halogen': 'var(--ggui-color-success-500, #22c55e)',
      'transition metal': 'var(--ggui-color-primary-500, #0ea5e9)',
      'alkaline earth metal': 'var(--ggui-color-warning-500, #f59e0b)',
    };
    return map[category.toLowerCase()] || 'var(--ggui-color-neutral-400, #9ca3af)';
  };

  return { search, setSearch, selected, setSelected, filtered, categories, getCategoryColor };
}

export default function Component(props: Props) {
  const { search, setSearch, selected, setSelected, filtered, categories, getCategoryColor } = useComponent(props);

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={16}>
        <Heading level={1}>Periodic Table</Heading>
        <Input label="Search" placeholder="Search by name or symbol..." value={search} onChange={setSearch} />

        <Box style={{ display: 'grid', gridTemplateColumns: 'repeat(18, 1fr)', gap: 'var(--ggui-spacing-1, 4px)', overflowX: 'auto' }}>
          {filtered.map(e => (
            <Card 
              key={e.atomicNumber}
              radius="sm"
              padding={8}
              style={{ 
                gridRow: e.row, 
                gridColumn: e.column
              }}
              border={true}
            >
              <div onClick={() => setSelected(e)} style={{ cursor: 'pointer', borderLeft: `4px solid ${getCategoryColor(e.category)}` }}>
                <Text variant="caption">{e.atomicNumber}</Text>
                <Heading level={6} style={{ textAlign: 'center' }}>{e.symbol}</Heading>
              </div>
            </Card>
          ))}
        </Box>

        {selected && (
          <Card padding={24} shadow="md">
            <Heading level={3}>{selected.name} ({selected.symbol})</Heading>
            <Stack gap={8} style={{ marginTop: 16 }}>
              <Text>Atomic Number: {selected.atomicNumber}</Text>
              <Text>Atomic Weight: {selected.atomicWeight}</Text>
              <Text>Category: {selected.category}</Text>
            </Stack>
          </Card>
        )}

        <Card padding={16} radius="lg">
          <Heading level={4} style={{ marginBottom: 12 }}>Legend</Heading>
          <Stack direction="horizontal" gap={16} wrap={true}>
            {categories.map(c => (
              <Stack direction="horizontal" key={c} align="center" gap={8}>
                <Box style={{ width: 12, height: 12, backgroundColor: getCategoryColor(c), borderRadius: '50%' }} />
                <Text variant="bodySmall">{c}</Text>
              </Stack>
            ))}
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

interface Props {
  properties: unknown;
}

// Action handlers (call these from event handlers):
//   props.actions: {"complete":{"label":"Complete Setup","description":"Called with all profile data when user completes onboarding","example":{"name":"Jane","email":"jane@example.com","avatar":"🧑‍💻","role":"Developer","emailNotifications":true,"theme":"dark"}}}
function useComponent(props: any) {
  const [step, setStep] = useState(1);
  const [data, setData] = useState({
    name: '',
    email: '',
    avatar: '🧑‍💻',
    role: 'Developer',
    emailNotifications: true,
    theme: 'light'
  });

  const isStep1Valid = useMemo(() => data.name.trim() !== '' && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(data.email), [data.name, data.email]);

  const next = () => setStep((s) => Math.min(s + 1, 3));
  const back = () => setStep((s) => Math.max(s - 1, 1));

  const complete = () => {
    if (props.actions?.complete) {
      props.actions.complete(data);
    }
  };

  return { step, data, setData, isStep1Valid, next, back, complete };
}

export default function Component(props: Props) {
  const { step, data, setData, isStep1Valid, next, back, complete } = useComponent(props);

  return (
    <Container maxWidth="sm" padding={24}>
      <Stack gap={24}>
        <Heading level={2} align="center">Setup your profile</Heading>
        <Progress value={(step - 1) * 50} max={100} />

        <Card padding={24}>
          {step === 1 && (
            <Stack gap={16}>
              <Input label="Name" value={data.name} onChange={(v) => setData({...data, name: v})} required />
              <Input label="Email" value={data.email} onChange={(v) => setData({...data, email: v})} required type="email" />
              <RadioGroup label="Avatar" value={data.avatar} onChange={(v) => setData({...data, avatar: v})} direction="horizontal" options={[{value:'🧑‍💻', label:'🧑‍💻'}, {value:'🎨', label:'🎨'}, {value:'📈', label:'📈'}, {value:'✨', label:'✨'}]} />
            </Stack>
          )}
          {step === 2 && (
            <Stack gap={16}>
              <Select label="Role" value={data.role} onChange={(v) => setData({...data, role: v})} options={[{value:'Developer', label:'Developer'}, {value:'Designer', label:'Designer'}, {value:'Manager', label:'Manager'}, {value:'Other', label:'Other'}]} />
              <Toggle label="Email notifications" checked={data.emailNotifications} onChange={(v) => setData({...data, emailNotifications: v})} />
              <Toggle label="Dark theme" checked={data.theme === 'dark'} onChange={(v) => setData({...data, theme: v ? 'dark' : 'light'})} />
            </Stack>
          )}
          {step === 3 && (
            <Stack gap={16}>
              <Text variant="label">Review details</Text>
              <Text variant="bodySmall">Name: {data.name}</Text>
              <Text variant="bodySmall">Email: {data.email}</Text>
              <Text variant="bodySmall">Role: {data.role}</Text>
            </Stack>
          )}
        </Card>

        <Row justify="between">
          <Button variant="ghost" onClick={back} disabled={step === 1}>Back</Button>
          {step < 3 ? (
            <Button onClick={next} disabled={step === 1 && !isStep1Valid}>Next</Button>
          ) : (
            <Button variant="primary" onClick={complete}>Complete Setup</Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
